import{_ as a,r as t,o as e,c as o,e as p,a as c,d as l,w as i,b as u}from"./app-cb4a12e2.js";const r={};function d(k,n){const s=t("RouterLink");return e(),o("div",null,[n[1]||(n[1]=p(`<h1 id="lab-03-the-brain-of-the-analyst" tabindex="-1"><a class="header-anchor" href="#lab-03-the-brain-of-the-analyst" aria-hidden="true">#</a> Lab 03: The Brain of the Analyst</h1><h1 id="实验-03-分析师的大脑" tabindex="-1"><a class="header-anchor" href="#实验-03-分析师的大脑" aria-hidden="true">#</a> 实验 03: 分析师的大脑</h1><h2 id="🧪-实验任务-tasks" tabindex="-1"><a class="header-anchor" href="#🧪-实验任务-tasks" aria-hidden="true">#</a> 🧪 实验任务 / Tasks</h2><h3 id="task-1-define-tools-定义工具" tabindex="-1"><a class="header-anchor" href="#task-1-define-tools-定义工具" aria-hidden="true">#</a> Task 1: Define Tools (定义工具)</h3><p>在 <code>apps/api</code> 中定义两个核心工具：</p><ol><li><p><strong>SQL Query Tool</strong>:</p><ul><li>输入: <code>sql_query</code> (string)</li><li>功能: 在数据库中执行 SQL，返回 JSON 数据。</li><li>安全: 仅限 SELECT 权限 (只读)。</li></ul></li><li><p><strong>Chart Config Tool</strong>:</p><ul><li>输入: <code>chart_type</code> (bar/line/pie), <code>x_axis</code> (field), <code>y_axis</code> (field), <code>title</code> (string)</li><li>功能: 生成 ECharts 的 <code>option</code> 对象。</li></ul></li></ol><p><strong>验证标准 / Acceptance Criteria:</strong></p><ul><li>单元测试覆盖工具逻辑。</li><li>模拟调用工具能返回预期结果。</li></ul><h3 id="task-2-implement-agent-logic-实现-agent-逻辑" tabindex="-1"><a class="header-anchor" href="#task-2-implement-agent-logic-实现-agent-逻辑" aria-hidden="true">#</a> Task 2: Implement Agent Logic (实现 Agent 逻辑)</h3><p>使用 OpenAI Function Calling API 或 LangChain：</p><ol><li>接收用户输入 (e.g., &quot;分析上个月的销售趋势&quot;)。</li><li>LLM 决定调用 <code>SQL Query Tool</code>。</li><li>执行 SQL，获取数据。</li><li>LLM 观察数据，决定调用 <code>Chart Config Tool</code>。</li><li>返回最终结果：文本解释 + 图表配置。</li></ol><p><strong>代码参考 / Code Snippet (Conceptual):</strong></p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">runAgent</span><span class="token punctuation">(</span>query<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> messages <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">{</span> role<span class="token operator">:</span> <span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span> content<span class="token operator">:</span> query <span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
  
  <span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> response <span class="token operator">=</span> <span class="token keyword">await</span> llm<span class="token punctuation">.</span><span class="token function">chat</span><span class="token punctuation">(</span><span class="token punctuation">{</span> messages<span class="token punctuation">,</span> tools<span class="token operator">:</span> <span class="token punctuation">[</span>sqlTool<span class="token punctuation">,</span> chartTool<span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">const</span> message <span class="token operator">=</span> response<span class="token punctuation">.</span>choices<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">.</span>message<span class="token punctuation">;</span>

    <span class="token keyword">if</span> <span class="token punctuation">(</span>message<span class="token punctuation">.</span>tool_calls<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token comment">// Execute tool</span>
      <span class="token keyword">const</span> toolResult <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">executeTool</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span>tool_calls<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      messages<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>message<span class="token punctuation">)</span><span class="token punctuation">;</span>
      messages<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token punctuation">{</span> role<span class="token operator">:</span> <span class="token string">&#39;tool&#39;</span><span class="token punctuation">,</span> content<span class="token operator">:</span> toolResult <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
      <span class="token keyword">return</span> message<span class="token punctuation">.</span>content<span class="token punctuation">;</span> <span class="token comment">// Final answer</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="task-3-frontend-streaming-chat-前端流式对话" tabindex="-1"><a class="header-anchor" href="#task-3-frontend-streaming-chat-前端流式对话" aria-hidden="true">#</a> Task 3: Frontend Streaming Chat (前端流式对话)</h3><p>在 <code>apps/web</code> 中实现：</p><ol><li>使用 <code>useChat</code> hook (Vercel AI SDK)。</li><li>自定义 <code>Message</code> 组件，支持渲染 Markdown 和 图表。</li><li>当消息包含 <code>chart_config</code> 时，渲染 ECharts 组件。</li></ol><p><strong>验证标准 / Acceptance Criteria:</strong></p><ul><li>对话流畅，打字机效果。</li><li>提问 &quot;画一个饼图&quot;，能正确显示饼图组件。</li></ul><h3 id="task-4-integration-test-集成测试" tabindex="-1"><a class="header-anchor" href="#task-4-integration-test-集成测试" aria-hidden="true">#</a> Task 4: Integration Test (集成测试)</h3><p>编写一个 E2E 测试 (Playwright)：</p><ol><li>打开页面。</li><li>输入 &quot;统计各产品类别的销售额&quot;。</li><li>验证页面出现了一个柱状图 (Bar Chart)。</li><li>验证图表数据与数据库一致。</li></ol><h2 id="✅-自动评分脚本-grading-script" tabindex="-1"><a class="header-anchor" href="#✅-自动评分脚本-grading-script" aria-hidden="true">#</a> ✅ 自动评分脚本 / Grading Script</h2><p>我们提供了一个 Jest 脚本来模拟 Agent 对话流程并验证输出结构。 请在 <code>03-project/lab</code> 目录下运行 <code>npm test</code>。</p><hr>`,24)),c("p",null,[l(s,{to:"/blogs/2026/AI-Agent-Data-Analyzer/03-project/"},{default:i(()=>[...n[0]||(n[0]=[u("Back to Module 03",-1)])]),_:1})])])}const g=a(r,[["render",d],["__file","index.html.vue"]]);export{g as default};
